scwin.onpageload = function () {
  const codeOptions_lc_unit = [{
    grpCd: "CO012",
    compID: "lc_unit"
  }];
  $c.data.setCommonCode($p, codeOptions_lc_unit);
  scwin.vLoginCoCd = $c.data.getMemInfo($p, "coCd"); // 소속 자회사  
  scwin.vLoginCoClsCd = $c.data.getMemInfo($p, "coClsCd"); // 회계_회사구분('CO035' : 0:동부 EXPRESS)
  scwin.vUserHomeClsCd = $c.data.getMemInfo($p, "userHomeClsCd"); // 사용자소속구분코드 
  scwin.vPrivAdmin = $c.data.getMemInfo($p, "privAdmin");
  $c.gus.cfDisableKey($p);
  scwin.f_FieldClear();
};

//-------------------------------------------------------------------------
// UDC값
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  ed_srchAcctDeptCd.setValue("00000");
  ed_srchAcctDeptNm.setValue("전사");
  lc_unit.setSelectedIndex(1);
  scwin.f_setCompanyInfo();
  $c.gus.cfDisableObjects($p, [ed_coCd, ed_coNm, btn_company]);
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function () {
  scwin.f_SetDefaultUnit();
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.f_SetDefaultUnit = function () {
  var rcnt = dlt_commonCodeCO012.getRowCount();
  if (rcnt < 1) return;
  var index = 0;
  for (i = 0; i < rcnt; i++) {
    if (dlt_commonCodeCO012.getCellData(i, "fltrCd1") == DGlobalValue.TRUE) {
      index = i;
      break;
    }
  }
  lc_unit.setSelectedIndex(index);
};

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
  $c.gus.cfInitObjects($p, tbl_search, [ed_srchCloseYm, lc_version]);
  scwin.f_SetSrchDefault();
  // chk_lowerDeptIncluYn.checkAll(false);
  // chk_distYn.checkAll(false);
  // chk_dpctYn.checkAll(false);
  // scwin.f_SetGridFormat(ed_srchCloseYm.getValue().trim());
};

//-------------------------------------------------------------------------
// 조회 기본값 설정
//-------------------------------------------------------------------------
scwin.f_SetSrchDefault = async function () {
  $c.gus.cfInitHidVal($p, tbl_search);
  ed_srchCloseYm.setValue(scwin.fromDate_YyMm);
  await scwin.f_CloseYm();
  await scwin.f_GetVersion();
  scwin.f_SetGridFormat(ed_srchCloseYm.getValue().trim());
  lc_acctDeptCd.setDisabled(true);
  ed_srchAcctDeptCd.setValue("00000");
  ed_srchAcctDeptNm.setValue("전사");
  if (scwin.f_IsPopUp(ed_srchAcctDeptCd, ed_srchAcctDeptNm)) scwin.f_deptPopUp();
  chk_lowerDeptIncluYn.checkAll(false);
  chk_distYn.checkAll(false);
  chk_dpctYn.checkAll(false);
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정   --> scwin.onUdcCompleted = function() 에서 호출
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function () {
  // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
  $c.gus.cfDisableObjects($p, [ed_coCd, ed_coNm, btn_company]);
  if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
    scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
    scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
  }
  if (scwin.vLoginCoCd == "") {
    ed_coCd.setValue("000");
    ed_coNm.setValue("동원로엑스(주)");
  } else {
    ed_coCd.setValue(scwin.vLoginCoCd);
    if (scwin.vLoginCoCd == "000") {
      ed_coNm.setValue("동원로엑스(주)");
    } else {
      scwin.f_PopUpCompanyInfo('T');
    }
  }
  // $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company]);    
};

//-------------------------------------------------------------------------
