scwin.f_Excel = async function () {
  if (gr_master.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  let str1 = $c.gus.cfGetFormatStr($p, ed_srchCloseYm.getValue().trim(), "######");
  let infoArr = [];
  const options = {
    fileName: "사업별총괄표_" + ed_srchAcctDeptNm.getValue() + "_" + str1 + "_ver_" + lc_version.getValue() + ".xlsx",
    sheetName: "사업별총괄표",
    startRowIndex: 0,
    startColumnIndex: 0,
    type: 1
  };
  await $c.data.downloadGridViewExcel($p, gr_master, options, infoArr);
};

