scwin.f_IsPopUp = function (inObj, inObjNm) {
  let inValue1 = $c.gus.cfGetValue($p, inObj);
  let inValue2 = $c.gus.cfGetValue($p, inObjNm);
  if ($c.gus.cfIsNull($p, inValue1)) {
    inObj.options.hidVal = "";
    inObjNm.setValue("");
    return false;
  }
  return true;
};

