scwin.ds_closeYm_ondataload = function () {
  if (ds_closeYm.getRowCount() > 0) {
    scwin.tcloseYm = ds_closeYm.getCellData(0, "col1");
    ed_srchCloseYm.setValue(scwin.tcloseYm);
    scwin.f_SetGridFormat(scwin.tcloseYm);
  } else {
    if (scwin.tcloseYm == "") {
      ed_srchCloseYm.setValue(scwin.fromDate_YyMm);
    }
  }
};
scwin.btn_search_onclick = async function (e) {
  if (ed_coCd.getValue().trim().length <= 0) {
    await $c.win.alert($p, "회사코드는 필수입력항목입니다.");
    return;
  }
  if (ed_srchCloseYm.getValue().trim().length <= 0) {
    await $c.win.alert($p, "결산년월은 필수입력항목입니다.");
    return;
  }
  if (lc_version.getValue().trim().length <= 0) {
    await $c.win.alert($p, "버전은 필수입력항목입니다.");
    return;
  }
  if (ed_srchAcctDeptCd.getValue().trim().length <= 0) {
    await $c.win.alert($p, "부서코드는 필수입력항목입니다.");
    return;
  }
  scwin.f_GetRsltsDept(e);
};
